"use strict";parserFactory.register("hiscension.com",()=>new HiscensionParser);class HiscensionParser extends WordpressBaseParser{constructor(){super()}getChapterUrls(e){let r=[...e.querySelectorAll("table.wp-block-table td a")].map(e=>util.hyperLinkToChapter(e));return Promise.resolve(r)}findContent(e){return e.querySelector("div.blog-post-single-content")}extractTitleImpl(e){return e.querySelector("article h1")}}